def mentor_chain_depth(spec: dict) -> int:
    """Deepest mentor-hop distance reachable from start via mentor edges only."""
    adj = {}
    for pair in spec["mentors"]:
        if pair[0] not in adj:
            adj[pair[0]] = []
        adj[pair[0]].append(pair[1])
    depth = {spec["start"]: 0}
    queue = [spec["start"]]
    best = 0
    while queue:
        n = queue.pop(0)
        if depth[n] > best:
            best = depth[n]
        if n in adj:
            for t in adj[n]:
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return best

