    has last: str = "";
    has switches: int = 0;
    can ride with Stop entry {
        road_next = [->:RoadLeg:->];
        rail_next = [->:RailLeg:->];
        if len(road_next) > 0 {
            if self.last != "" and self.last != "road" { self.switches += 1; }
            self.last = "road";
            visit road_next;
