    reg: dict = {};
    for leg in legs { for nm in [leg[0], leg[1]] { if nm not in reg { reg[nm] = Stop(name=nm); } } }
    for leg in legs {
        if leg[2] == "road" { reg[leg[0]] +>:RoadLeg:+> reg[leg[1]]; }
        else { reg[leg[0]] +>:RailLeg:+> reg[leg[1]]; }
    }
    wk = reg[legs[0][0]] spawn Transfers();
    return wk.switches;
}

