def interchange_names(spec: dict) -> list:
    """Sorted names of reachable nodes that have both an outgoing road and an outgoing rail."""
    road_adj = {}
    for pair in spec["roads"]:
        if pair[0] not in road_adj:
            road_adj[pair[0]] = []
        road_adj[pair[0]].append(pair[1])
    rail_adj = {}
    for pair in spec["rails"]:
        if pair[0] not in rail_adj:
            rail_adj[pair[0]] = []
        rail_adj[pair[0]].append(pair[1])
    seen = set()
    stack = [spec["start"]]
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        if n in road_adj:
            stack.extend(road_adj[n])
        if n in rail_adj:
            stack.extend(rail_adj[n])
    hits = []
    for n in seen:
        if n in road_adj and n in rail_adj:
            hits.append(n)
    return sorted(hits)

